import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"Fielding Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/fielding.md","filePath":"analytics/fielding.md"}'),r={name:"analytics/fielding.md"};function o(s,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="fielding-analytics" tabindex="-1">Fielding Analytics <a class="header-anchor" href="#fielding-analytics" aria-label="Permalink to &quot;Fielding Analytics&quot;">​</a></h1><h2 id="fielding-percentage" tabindex="-1">Fielding Percentage <a class="header-anchor" href="#fielding-percentage" aria-label="Permalink to &quot;Fielding Percentage&quot;">​</a></h2><p>FLD% = (Putouts + Assists) ÷ (Putouts + Assists + Errors)</p><p>For catchers, passed balls are included as errors in the FLD% calculation.</p><h2 id="zone-tendency-chart" tabindex="-1">Zone Tendency Chart <a class="header-anchor" href="#zone-tendency-chart" aria-label="Permalink to &quot;Zone Tendency Chart&quot;">​</a></h2><p>The polar accuracy chart shows fielding accuracy by directional zone. Each segment represents a zone around the fielder. The size and color of each segment indicates how often balls were successfully fielded vs errored in that zone.</p><p>Use this to identify directional weaknesses — for example a shortstop who struggles on balls to his backhand side.</p><h2 id="throwing-analytics" tabindex="-1">Throwing Analytics <a class="header-anchor" href="#throwing-analytics" aria-label="Permalink to &quot;Throwing Analytics&quot;">​</a></h2><p>A separate throwing accuracy chart shows throw results by direction. Each segment represents a throw zone and indicates accuracy rate.</p><h2 id="position-filter" tabindex="-1">Position Filter <a class="header-anchor" href="#position-filter" aria-label="Permalink to &quot;Position Filter&quot;">​</a></h2><p>Filter fielding analytics by position to analyze performance at each position separately. A player may excel at one position while struggling at another.</p><h2 id="tap-for-detail" tabindex="-1">Tap for Detail <a class="header-anchor" href="#tap-for-detail" aria-label="Permalink to &quot;Tap for Detail&quot;">​</a></h2><p>Tap any zone segment on the polar chart to see the specific plays that contributed to that zone&#39;s data.</p>',13)])])}const g=a(r,[["render",o]]);export{f as __pageData,g as default};
